select e.id, p.bill_no as billNo, p.stocktaking_no as stocktakingNo, w.name as warehouseName, m.code as materialCode, m.name as materialName, m.speci as materialSpeci, m.model as materialModel, u.unit_name as unitName, e.batch_no as batchNo, e.book_qty as bookQty, e.stock_qty as stockQty, e.profit_qty as profitQty, e.unit_price as unitPrice, e.profit_amount as profitAmount, p.create_time as createTime, cu.nick_name as createrName, p.audit_date as auditDate, au.user_name as auditBy from stk_io_profit_loss_entry e left join stk_io_profit_loss p on e.paren_id = p.id left join fd_warehouse w on p.warehouse_id = w.id left join fd_material m on e.material_id = m.id left join fd_unit u on m.unit_id = u.unit_id left join sys_user cu on p.create_by = cu.user_id left join sys_user au on p.audit_by = au.user_id
(e.del_flag is null or e.del_flag != 1) and (p.del_flag is null or p.del_flag != 1) and p.tenant_id = #{scopedTenantId} and p.bill_no like concat('%', #{billNo}, '%') and p.stocktaking_no like concat('%', #{stocktakingNo}, '%') and p.warehouse_id = #{warehouseId} and (m.name like concat('%', #{materialName}, '%') or m.code like concat('%', #{materialName}, '%')) and DATE(p.create_time) >= #{beginDate} and DATE(p.create_time) <= #{endDate}
order by p.create_time desc, e.id desc

select m.id as materialId, m.code as materialCode, m.name as materialName, m.speci as materialSpeci, m.model as materialModel, u.unit_name as unitName, AVG(e.unit_price) as unitPrice, SUM(e.profit_qty) as profitQty, SUM(e.profit_amount) as profitAmount, w.name as warehouseName from stk_io_profit_loss_entry e left join stk_io_profit_loss p on e.paren_id = p.id left join fd_warehouse w on p.warehouse_id = w.id left join fd_material m on e.material_id = m.id left join fd_unit u on m.unit_id = u.unit_id
(e.del_flag is null or e.del_flag != 1) and (p.del_flag is null or p.del_flag != 1) and p.tenant_id = #{scopedTenantId} and p.warehouse_id = #{warehouseId} and (m.name like concat('%', #{materialName}, '%') or m.code like concat('%', #{materialName}, '%')) and DATE(p.create_time) >= #{beginDate} and DATE(p.create_time) <= #{endDate}
group by m.id, m.code, m.name, m.speci, m.model, u.unit_name, w.name order by m.code


select
    COALESCE(SUM(e.profit_qty), 0) as totalQty,
    COALESCE(SUM(e.profit_amount), 0) as totalAmt
from stk_io_profit_loss_entry e
left join stk_io_profit_loss p on e.paren_id = p.id

